function solve(nums: number[], k: number): number {
    let totalSum = 0;
    let modCount = 0;

    for (const num of nums) {
        totalSum += num;
        modCount = (modCount + num % k + k) % k; // Ensure non-negative modulo
    }

    // If the total sum is divisible by k, we can remove the entire array
    if (modCount === 0) {
        return 0;
    }

    // Find the minimum remainder that can be removed
    let minRemainder = k;
    for (const num of nums) {
        const remainder = num % k;
        if (remainder < minRemainder) {
            minRemainder = remainder;
        }
    }

    // The minimum possible sum is the total sum minus the minimum remainder
    return totalSum - minRemainder;
}

